// src/data/qtypes.ts
// Thư viện "Dạng đề" — song ngữ { vi, en }. built=false => "Sắp có".
export interface Bi { vi: string; en: string }
export interface QSection { heading: Bi; body: Bi }
export interface QType {
  id: string; skill: "Writing" | "Reading" | "Listening" | "Speaking";
  group: string; name: Bi; summary: Bi; built: boolean; sections?: QSection[];
}
export const SKILL_ORDER = ["Listening", "Reading", "Writing", "Speaking"] as const;

const S = (vi: string, en: string): Bi => ({ vi, en });
const sec = (hvi: string, hen: string, bvi: string, ben: string): QSection => ({ heading: S(hvi, hen), body: S(bvi, ben) });

